.darma-loader-uiverse-solar-loading-dial__loading-bar {
  position: relative;
  width: 110px;
  height: 110px;
  background: transparent;
  border: 3px solid var(--loader-secondary-color, #3c3c3c);
  border-radius: 50%;
  text-align: center;
  line-height: 111px;
  font-family: sans-serif;
  font-size: 15px;
  color: var(--loader-color, #fff000);
  letter-spacing: 3px;
  text-transform: uppercase;
  text-shadow: 0 0 20px var(--loader-color, #fff000);
  box-shadow: 0 0 20px rgba(0,0,0,.5);
}
.darma-loader-uiverse-solar-loading-dial__loading-bar::before {
  content: "";
  position: absolute;
  top: -3px;
  left: -3px;
  width: 100%;
  height: 100%;
  border: 3px solid transparent;
  border-top: 5px solid var(--loader-color, #fff000);
  border-right: 5px solid var(--loader-color, #fff000);
  border-radius: 50%;
  animation: darma-loader-uiverse-solar-loading-dial-solarDial 2s linear infinite;
}
.darma-loader-uiverse-solar-loading-dial__loading-bar span {
  position: absolute;
  top: calc(50% - 2px);
  left: 50%;
  width: 50%;
  height: 4px;
  background: transparent;
  transform-origin: left;
  animation: darma-loader-uiverse-solar-loading-dial-solarHand 2s linear infinite;
}
.darma-loader-uiverse-solar-loading-dial__loading-bar span::before {
  content: "";
  position: absolute;
  width: 14px;
  height: 14px;
  border-radius: 50%;
  background: var(--loader-color, #fff000);
  top: -5px;
  right: -7px;
  box-shadow: 0 0 20px var(--loader-color, #fff000);
}
@keyframes darma-loader-uiverse-solar-loading-dial-solarDial { to { transform: rotate(360deg); } }
@keyframes darma-loader-uiverse-solar-loading-dial-solarHand { from { transform: rotate(45deg); } to { transform: rotate(405deg); } }

